    if not match:
        raise ValueError(f"Invalid token in payload: {token!r}")

    letters, number_text = match.groups()
    letter_value = 0
    for ch in letters:
        letter_value = letter_value * 26 + (ord(ch) - ord("A") + 1)

    return letter_value * int(number_text)


