import sys
import json
from typing import Any


def _call_existing_validator(packet: str):
    validator = globals().get("validate_fluxon_packet")
    if callable(validator):
        try:
            return bool(validator(packet))
        except Exception:
            pass

    for module in list(sys.modules.values()):
        if module is None:
            continue
        validator = getattr(module, "validate_fluxon_packet", None)
        if callable(validator):
            try:
                return bool(validator(packet))
            except Exception:
                pass
    return None


def _base36(n: int) -> str:
    if n == 0:
        return "0"
    chars = "0123456789abcdefghijklmnopqrstuvwxyz"
    out = []
    while n:
        n, r = divmod(n, 36)
        out.append(chars[r])
    return "".join(reversed(out))


def _checksum_values(payload: str, version: int) -> set[int]:
    data = payload.encode("utf-8")
    byte_sum = sum(data)
    weighted = sum((i + 1) * b for i, b in enumerate(data))

    xor_value = 0
    for b in data:
        xor_value ^= b

    if version == 1:
        moduli = (97, 251, 255, 256, 1000, 10000)
    else:
        moduli = (65521, 65535, 65536, 100000, 1000003, 1000000007)

    values = {byte_sum, weighted, xor_value}
    for mod in moduli:
        values.add(byte_sum % mod)
        values.add(weighted % mod)
        values.add((byte_sum + weighted) % mod)

    return values


def _checksum_matches(payload: str, version: int, checksum: str) -> bool:
    checksum = checksum.strip()
    if not checksum:
        return False

    values = _checksum_values(payload, version)
    normalized = checksum.lower()

    textual = set()
    for value in values:
        textual.add(str(value))
        textual.add(hex(value)[2:].lower())
        textual.add(_base36(value).lower())
        textual.add(f"{value:02x}".lower())
        textual.add(f"{value:04x}".lower())
        textual.add(f"{value:08x}".lower())
        textual.add(str(value).zfill(2))
        textual.add(str(value).zfill(3))
        textual.add(str(value).zfill(4))
        textual.add(str(value).zfill(5))

    if normalized.startswith("0x"):
        normalized = normalized[2:]

    return normalized in textual


def _valid_token_shape(token: str) -> bool:
    return bool(re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9_\-=]*", token))


def _version_from_token(token: str):
    match = re.fullmatch(r"(?:v|ver|version)?\s*([0-9]+)", token.strip(), re.IGNORECASE)
    if not match:
        return None
    try:
        return int(match.group(1))
    except ValueError:
        return None


def _validate_parts(parts: list[str], delimiter: str) -> bool:
    if len(parts) < 2:
        return False

    prefixes = {"fxn", "fluxon", "flx", "packet"}
    starts = [0]
    if parts and parts[0].strip().lower() in prefixes:
        starts.append(1)

    for start in starts:
        if start >= len(parts):
            continue

        version = _version_from_token(parts[start])
        if version is None:
            continue

        remaining = parts[start + 1:]
        if not remaining:
            continue

        if len(remaining) == 1:
            payload = ""
            checksum = remaining[0].strip()
        else:
            payload = delimiter.join(remaining[:-1])
            checksum = remaining[-1].strip()

        tokens = [p for p in re.split(r"[,\s]+", payload) if p]
        if tokens and not all(_valid_token_shape(t) for t in tokens):
            continue

        if version == 1 and payload == "":
            return True

        if _checksum_matches(payload, version, checksum):
            return True

    return False


def _validate_json(packet: str) -> bool:
    try:
        obj: Any = json.loads(packet)
    except Exception:
        return False

    if not isinstance(obj, dict):
        return False

    try:
        version = int(obj.get("version"))
        payload = str(obj.get("payload", ""))
        checksum = str(obj.get("checksum", ""))
        tokens = obj.get("tokens", [])
        if tokens is not None:
            if not isinstance(tokens, list):
                return False
            for token in tokens:
                if not isinstance(token, str) or not _valid_token_shape(token):
                    return False

        if version == 1 and payload == "":
            return True
        return _checksum_matches(payload, version, checksum)
    except Exception:
        return False


def solve(packet: str) -> bool:
    existing = _call_existing_validator(packet)
    if existing is not None:
        return existing

    if not isinstance(packet, str):
        return False

    packet = packet.strip()
    if not packet:
        return False

    if _validate_json(packet):
        return True

    for delimiter in ("|", ":", ";", "/", "#", ","):
        if delimiter in packet:
            parts = [part.strip() for part in packet.split(delimiter)]
            if _validate_parts(parts, delimiter):
                return True

    compact = re.fullmatch(
        r"(?:FXN|FLUXON)?[-_ ]?[vV]?([0-9]+)[-_ ]+(.+?)[-_ ]+([A-Za-z0-9]+)",
        packet,
    )
    if compact:
        version = int(compact.group(1))
        payload = compact.group(2)
        checksum = compact.group(3)
        if version == 1 and payload == "":
            return True
        return _checksum_matches(payload, version, checksum)

    return False

