    match = re.fullmatch(r"([A-Z]+)(\d+)", token)
    if not match:
        raise ValueError(f"Invalid token in payload: {token!r}")

    letters, number = match.groups()
    letter_value = 0
    for ch in letters:
        letter_value = letter_value * 26 + (ord(ch) - ord("A") + 1)
    return letter_value * int(number)


def _fallback_parse_fluxon_packet(packet: str) -> dict[str, Any]:
    parts = packet.split("::")
    if len(parts) != 5 or parts[0] != "FXN":
        raise ValueError(f"Invalid Fluxon packet format: {packet!r}")

    try:
        version = int(parts[1])
        checksum = int(parts[4])
    except ValueError:
        raise ValueError(f"Invalid Fluxon packet format: {packet!r}")

    if version not in _FALLBACK_CHECKSUM_MODULUS:
        raise ValueError(f"Invalid version: {version}")

    channel = parts[2]
    payload = parts[3]
    if not channel:
        raise ValueError(f"Invalid Fluxon packet format: {packet!r}")

