    tokens = []
    versions = []
    channels = []

    for record in records:
        payloads.append(record["payload"])
        tokens.extend(record["tokens"])
        versions.append(record["version"])
        channels.append(record["channel"])

    counts = {}
    for channel in channels:
        counts[channel] = counts.get(channel, 0) + 1

    dominant_channel = max(channels, key=lambda c: (counts[c], -channels.index(c)))

    return {
        "version": max(versions),
        "channel": dominant_channel,
        "payload": "-".join(payloads) if any(payloads) else "",
